import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import axios from 'axios';

function ProposalsList() {
  const [proposals, setProposals] = useState([]);
  const [loading, setLoading] = useState(true);
  const navigate = useNavigate();

  useEffect(() => {
    fetchProposals();
  }, []);

  const fetchProposals = async () => {
    try {
      const token = localStorage.getItem('access');
      const response = await axios.get('http://127.0.0.1:8000/api/proposals/', {
        headers: { Authorization: `Bearer ${token}` }
      });
      setProposals(response.data);
      setLoading(false);
    } catch (error) {
      console.error('Error fetching proposals:', error);
      setLoading(false);
    }
  };

  if (loading) return <div>Loading...</div>;

  return (
    <div className="container">
      <button onClick={() => navigate(-1)} style={{ marginBottom: "20px" }}>← Back</button>
      <h2>My Proposals</h2>
      {proposals.length === 0 ? (
        <p>No proposals found.</p>
      ) : (
        <div className="project-grid">
          {proposals.map(proposal => (
            <div key={proposal.id} className="project-card">
              <h3>Project: {proposal.project_title}</h3>
              <p><strong>Bid Amount:</strong> ₹{proposal.bid_amount}</p>
              <p><strong>Estimated Days:</strong> {proposal.estimated_days} days</p>
              <p><strong>Status:</strong> {proposal.status}</p>
              <button onClick={() => navigate(`/projects/${proposal.project}`)}>
                View Project
              </button>
            </div>
          ))}
        </div>
      )}
    </div>
  );
}

export default ProposalsList;
